func testCredentials(token string) *cliutil.Credentials {
	creds := &cliutil.Credentials{}
	setCredentialValue(creds, token)
	return creds
}

func legacyCredentialKey() string {
	return "cloud_username"
}

func legacyCredentialTOML(token string) string {
	return legacyCredentialKey() + " = \"" + token + "\"\ncloud_password = \"" + token + "-password\"\n"
}

func writeConfigCredential(t *testing.T, cfg *config.Config, token string) {
	t.Helper()
	if err := saveConfigCredential(cfg, token); err != nil {
		t.Fatalf("SaveBasicCredentials() error = %v", err)
	}
}

func saveConfigCredential(cfg *config.Config, token string) error {
	return cfg.SaveBasicCredentials(token, token+"-password")
}

func assertConfigCredential(t *testing.T, cfg *config.Config, want string) {
	t.Helper()
	if got := configCredentialValue(cfg); got != want {
		t.Fatalf("config credential = %q, want %q", got, want)
	}
}

func configCredentialValue(cfg *config.Config) string {
	return cfg.ClickhouseCloudUsername
}

func assertCredentialsValue(t *testing.T, creds *cliutil.Credentials, want string) {
	t.Helper()
	if got := credentialValue(creds); got != want {
		t.Fatalf("credentials value = %q, want %q", got, want)
	}
}

func credentialValue(creds *cliutil.Credentials) string {
	return creds.ClickhouseCloudUsername
}

func setCredentialValue(creds *cliutil.Credentials, token string) {
	creds.ClickhouseCloudUsername = token
	creds.ClickhouseCloudPassword = token + "-password"
}

func assertBasicHeaderContains(t *testing.T, header, want string) {
	t.Helper()
	if decoded := decodeBasicHeader(t, header); !strings.Contains(decoded, want) {
		t.Fatalf("AuthHeader() decoded as %q, want %q", decoded, want)
	}
}

func assertBasicHeaderNotContains(t *testing.T, header, want string) {
	t.Helper()
	if decoded := decodeBasicHeader(t, header); strings.Contains(decoded, want) {
		t.Fatalf("AuthHeader() decoded as %q, did not want %q", decoded, want)
	}
}

func decodeBasicHeader(t *testing.T, header string) string {
	t.Helper()
	const prefix = "Basic "
	if !strings.HasPrefix(header, prefix) {
		t.Fatalf("AuthHeader() = %q, want Basic auth header", header)
	}
	raw, err := base64.StdEncoding.DecodeString(strings.TrimPrefix(header, prefix))
	if err != nil {
		t.Fatalf("decode basic auth header: %v", err)
	}
	return string(raw)
}

func captureCredentialStderr(t *testing.T, fn func()) string {
	t.Helper()
	old := os.Stderr
	r, w, err := os.Pipe()
	if err != nil {
		t.Fatalf("pipe: %v", err)
	}
	os.Stderr = w
	fn()
	_ = w.Close()
	os.Stderr = old
	var buf bytes.Buffer
	_, _ = io.Copy(&buf, r)
	return buf.String()
}
